import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { combineLatest, map } from 'rxjs';
import { Location } from '../../core/models';

@Component({
  selector: 'app-admin-locations',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './admin-locations.component.html',
  styleUrls: ['./admin-locations.component.css'],
})
export class AdminLocationsComponent {
  form: FormGroup;
  saving = signal(false);

  readonly locations = signal<Location[]>([
    { id: 'L1', name: 'Main Warehouse', zone: 'A' },
    { id: 'L2', name: 'Overflow Depot', zone: 'B' },
    { id: 'L3', name: 'Front Store', zone: 'C' },
  ]);

  private readonly ctx = toSignal(
    combineLatest([this.route.paramMap, this.route.queryParamMap]).pipe(
      map(([p, q]) => ({ id: p.get('id'), isNew: q.get('form') === 'new' })),
    ),
    { initialValue: { id: null as string | null, isNew: false } },
  );

  readonly editId = computed(() => this.ctx().id);
  readonly showForm = computed(() => this.ctx().isNew || !!this.ctx().id);
  readonly editing = computed<Location | undefined>(() =>
    this.editId() ? this.locations().find((l) => l.id === this.editId()) : undefined,
  );

  constructor(
    private fb: FormBuilder,
    private route: ActivatedRoute,
    private router: Router,
  ) {
    this.form = this.fb.group({
      name: ['', Validators.required],
      zone: ['', Validators.required],
    });
    this.route.paramMap.subscribe(() => {
      const loc = this.editing();
      if (loc) {
        this.form.patchValue({ name: loc.name, zone: loc.zone });
      } else {
        this.form.reset({ name: '', zone: '' });
      }
    });
  }

  save(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.saving.set(true);
    setTimeout(() => {
      this.saving.set(false);
      this.router.navigate(['/admin/locations']);
    }, 300);
  }

  remove(loc: Location): void {
    this.locations.update((list) => list.filter((l) => l.id !== loc.id));
  }

  cancel(): void {
    this.router.navigate(['/admin/locations']);
  }
}
